import React, { useState } from "react";
import { Box, Button, Container, TextField, Typography, Paper, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { useAuth } from "../contexts/AuthContext";

export default function Login() {
  const navigate = useNavigate();
  const { login } = useAuth();
  const [formData, setFormData] = useState({ mobile: "" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e) => setFormData(p => ({ ...p, [e.target.name]: e.target.value }));

  const validateMobile = () => {
    const mobileRegex = /^[6-9]\d{9}$/;
    if (!mobileRegex.test(formData.mobile)) { setError("Mobile must start with 6-9 and 10 digits"); return false; }
    setError(""); return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateMobile()) return;
    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", formData);
      if (res.data.success) {
        login(res.data.user); // Save user in context
        navigate("/booking");
      } else setError(res.data.message || "Login failed");
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally { setLoading(false); }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered" }}>Rider App</Typography>
        <Typography variant="body1" align="center" sx={{ mb: 3 }}>Welcome back! Please login</Typography>
        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField fullWidth type="tel" label="Mobile Number" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" inputProps={{ maxLength: 10 }} required />

          <Button type="submit" fullWidth variant="contained" sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }} disabled={loading}>
            {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Login"}
          </Button>
        </Box>

        <Typography align="center" sx={{ mt: 2 }}>
          Don’t have aan account? <Button variant="text" onClick={() => navigate("/register")} sx={{ color: "orangered" }}>Sign Up</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
